165	    fn record_trajectory(
166	        &self,
167	        query: &str,
168	        context: &str,
169	        messages: &[Message],
170	        telemetry: &DepthTelemetry,
171	        final_answer: &str,
172	    ) {
173	        if let Some(sink) = self.config.trace_sink.as_ref() {
174	            let usage = self.usage.lock().map(|g| g.clone()).unwrap_or_default();
175	            let traj = Trajectory {
176	                trace_id: new_trace_id(),
177	                timestamp: rfc3339_now(),
178	                query: query.to_string(),
179	                context_chars: context.chars().count(),
180	                model: self.config.model.clone(),
181	                sub_model: self.config.sub_model.clone(),
182	                depth: self.config.depth,
183	                max_depth: self.config.max_depth,
184	                max_iterations: self.config.max_iterations,
185	                policy_profile: self.config.runtime_policy.profile_name.clone(),
186	                final_answer: final_answer.to_string(),
187	                messages: messages.to_vec(),
188	                telemetry: TrajectoryTelemetry::from(telemetry),
189	                usage,
190	            };
