226	        if let Some(policy_block) = self.config.runtime_policy.prompt_instruction_block() {
227	            messages.push(Message::system(&policy_block));
228	        }
229	
230	        for iteration in 0..self.config.max_iterations {
231	            messages.push(prompts::next_action_prompt(query, iteration, false));
232	
233	            let prompt_chars: usize = messages.iter().map(|m| m.content.len()).sum();
234	            let completion = self.llm.completion(&messages).await?;
235	            self.accumulate_usage(
